import { useState, useEffect, useMemo } from 'react';

const sortableColumns = ['id', 'name', 'age'];

const tableComponent = () => {
  const [records, setRecords] = useState([
    { id: 1, name: 'adam', age: 25 },
    { id: 2, name: 'james', age: 30 },
    { id: 3, name: 'nick', age: 28 },
    { id: 4, name: 'john', age: 29 }
  ]);

  const [filter, setFilter] = useState('');
  const [sortColumn, setSortColumn] = useState('id');
  const [sortDirection, setSortDirection] = useState('asc');

  // handle filter change
  const handleFilterChange = (e) => {
    setFilter(e.target.value.toLowerCase());
  };

  // handle sort column change
  const handleSort = (column) => {
    if (column !== sortColumn) {
      setSortColumn(column);
      setSortDirection('asc');
    } else {
      setSortDirection(sortDirection === 'asc' ? 'desc' : 'asc');
    }
  };

  // sort and filter the records
  const sortedAndFilteredRecords = useMemo(() => {
    let filtered = records.filter((record) =>
      record.name.toLowerCase().includes(filter)
    );

    if (sortColumn && sortDirection) {
      filtered = filtered.sort((a, b) => {
        if (a[sortColumn] < b[sortColumn]) return sortDirection === 'asc' ? -1 : 1;
        if (a[sortColumn] > b[sortColumn]) return sortDirection === 'asc' ? 1 : -1;
        return 0;
      });
    }

    return filtered;
  }, [records, filter, sortColumn, sortDirection]);

  return (
    <div>
      <input
        type="text"
        placeholder="filter by name"
        value={filter}
        onChange={handleFilterChange}
      />
      <table border="1" cellPadding="5" cellSpacing="0">
        <thead>
          <tr>
            <th onClick={() => handleSort('id')}>id</th
